head.b:skin:
/* ========== RESET & BASE ========== */
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    background: linear-gradient(135deg, #0c0c1e 0%, #1a1a3e 50%, #0c0c1e 100%);
    color: #e0e0e0;
    min-height: 100vh;
}

a {
    text-decoration: none;
    color: inherit;
    transition: color 0.3s ease;
}

a:hover {
    color: #00d4ff;
}

/* ========== LAYOUT ========== */
.container {
    display: flex;
    min-height: 100vh;
}

/* ========== VERTICAL MENU ========== */
.vertical-menu {
    width: 260px;
    background: linear-gradient(180deg, #1a1a2e 0%, #0f0f1e 100%);
    color: #e0e0e0;
    padding: 0;
    position: fixed;
    height: 100%;
    overflow-y: auto;
    z-index: 1000;
    border-right: 1px solid #2a2a4e;
    box-shadow: 4px 0 15px rgba(0, 0, 0, 0.3);
}

.menu-header {
    padding: 25px 20px;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    text-align: center;
}

.menu-header h1 {
    font-size: 24px;
    font-weight: bold;
    color: white;
    text-shadow: 2px 2px 4px rgba(0,0,0,0.3);
    margin-bottom: 5px;
}

.menu-header p {
    font-size: 12px;
    color: rgba(255,255,255,0.8);
}

.vertical-menu ul {
    list-style-type: none;
}

.vertical-menu li {
    position: relative;
}

.vertical-menu a {
    display: block;
    color: #b0b0b0;
    padding: 14px 20px;
    transition: all 0.3s ease;
    border-left: 3px solid transparent;
    font-size: 14px;
}

.vertical-menu a:hover {
    background-color: rgba(102, 126, 234, 0.1);
    border-left-color: #667eea;
    color: #fff;
    padding-left: 25px;
}

.vertical-menu > ul > li > a {
    font-weight: 600;
    font-size: 15px;
}

.vertical-menu ul ul {
    display: none;
    background-color: #0a0a1a;
}

.vertical-menu li:hover > ul {
    display: block;
}

.vertical-menu ul ul a {
    padding-left: 45px;
    font-weight: normal;
    font-size: 13px;
}

.vertical-menu ul ul ul a {
    padding-left: 65px;
}

.menu-icon {
    width: 25px;
    display: inline-block;
    margin-right: 10px;
    text-align: center;
}

/* ========== MAIN CONTENT ========== */
.main-content {
    margin-left: 260px;
    flex: 1;
    padding: 20px 30px;
}

/* ========== VIDEO PLAYER SECTION ========== */
.video-section {
    background: rgba(20, 20, 40, 0.8);
    border-radius: 15px;
    padding: 25px;
    margin-bottom: 30px;
    box-shadow: 0 10px 40px rgba(0, 0, 0, 0.4);
    border: 1px solid #2a2a4e;
}

.video-section h2 {
    font-size: 22px;
    margin-bottom: 20px;
    color: #fff;
    display: flex;
    align-items: center;
    gap: 10px;
}

.video-section h2 i {
    color: #667eea;
}

#artplayer {
    width: 100%;
    aspect-ratio: 16/9;
    border-radius: 10px;
    overflow: hidden;
    box-shadow: 0 5px 30px rgba(102, 126, 234, 0.3);
}

/* Artplayer custom styling */
.artplayer-layer-icon {
    filter: drop-shadow(0 2px 4px rgba(0,0,0,0.5));
}

/* ========== VIDEO INFO ========== */
.video-info {
    margin-top: 20px;
    padding: 20px;
    background: rgba(30, 30, 60, 0.6);
    border-radius: 10px;
}

.video-info h1 {
    font-size: 24px;
    color: #fff;
    margin-bottom: 15px;
}

.video-meta {
    display: flex;
    flex-wrap: wrap;
    gap: 20px;
    margin-bottom: 15px;
    font-size: 14px;
    color: #a0a0a0;
}

.video-meta span {
    display: flex;
    align-items: center;
    gap: 5px;
}

.video-meta i {
    color: #667eea;
}

.video-description {
    color: #c0c0c0;
    line-height: 1.8;
    font-size: 15px;
}

/* ========== SHARE BUTTONS ========== */
.share-buttons {
    display: flex;
    gap: 10px;
    margin-top: 20px;
    flex-wrap: wrap;
}

.share-btn {
    padding: 10px 20px;
    border-radius: 8px;
    color: white;
    font-weight: 600;
    display: flex;
    align-items: center;
    gap: 8px;
    transition: transform 0.3s, box-shadow 0.3s;
}

.share-btn:hover {
    transform: translateY(-3px);
    box-shadow: 0 5px 15px rgba(0,0,0,0.3);
}

.share-btn.facebook { background: linear-gradient(135deg, #1877f2, #0d5aba); }
.share-btn.twitter { background: linear-gradient(135deg, #1da1f2, #0d8bd9); }
.share-btn.telegram { background: linear-gradient(135deg, #0088cc, #006699); }
.share-btn.zalo { background: linear-gradient(135deg, #0068ff, #004ecc); }
.share-btn.copy { background: linear-gradient(135deg, #6c757d, #545b62); }

/* ========== EPISODE LIST ========== */
.episodes-section {
    background: rgba(20, 20, 40, 0.8);
    border-radius: 15px;
    padding: 25px;
    margin-bottom: 30px;
    box-shadow: 0 10px 40px rgba(0, 0, 0, 0.4);
    border: 1px solid #2a2a4e;
}

.episodes-section h3 {
    font-size: 20px;
    margin-bottom: 20px;
    color: #fff;
    display: flex;
    align-items: center;
    gap: 10px;
}

.episodes-section h3 i {
    color: #667eea;
}

.episodes-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(150px, 1fr));
    gap: 15px;
}

.episode-item {
    background: linear-gradient(135deg, #2a2a4e, #1a1a3e);
    border-radius: 10px;
    padding: 15px;
    text-align: center;
    transition: all 0.3s ease;
    cursor: pointer;
    border: 2px solid transparent;
}

.episode-item:hover {
    transform: translateY(-5px);
    border-color: #667eea;
    box-shadow: 0 5px 20px rgba(102, 126, 234, 0.4);
}

.episode-item.active {
    border-color: #667eea;
    background: linear-gradient(135deg, #667eea, #764ba2);
}

.episode-number {
    font-size: 24px;
    font-weight: bold;
    color: #fff;
    margin-bottom: 5px;
}

.episode-title {
    font-size: 12px;
    color: #b0b0b0;
}

.episode-item.active .episode-title {
    color: rgba(255,255,255,0.9);
}

/* ========== SLIDESHOW / FEATURED VIDEOS ========== */
.slideshow-container {
    position: relative;
    max-width: 100%;
    margin: 0 auto 30px auto;
    border-radius: 15px;
    overflow: hidden;
    box-shadow: 0 10px 40px rgba(0, 0, 0, 0.5);
}

.slideshow-slide {
    display: none;
    text-align: center;
}

.slideshow-slide img {
    width: 100%;
    height: 350px;
    object-fit: cover;
}

.slideshow-slide-content {
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    background: linear-gradient(transparent, rgba(0,0,0,0.9));
    color: white;
    padding: 30px 25px 25px 25px;
    text-align: left;
}

.slideshow-slide-content h3 {
    font-size: 24px;
    margin-bottom: 10px;
    color: #fff;
}

.slideshow-slide-content p {
    font-size: 14px;
    color: #c0c0c0;
}

.slideshow-prev, .slideshow-next {
    position: absolute;
    top: 50%;
    transform: translateY(-50%);
    background-color: rgba(102, 126, 234, 0.8);
    color: white;
    padding: 16px;
    cursor: pointer;
    border: none;
    user-select: none;
    font-size: 18px;
    z-index: 100;
    border-radius: 50%;
    width: 50px;
    height: 50px;
    transition: all 0.3s;
}

.slideshow-prev:hover, .slideshow-next:hover {
    background-color: rgba(102, 126, 234, 1);
    transform: translateY(-50%) scale(1.1);
}

.slideshow-prev { left: 20px; }
.slideshow-next { right: 20px; }

.slideshow-dots {
    position: absolute;
    bottom: 20px;
    left: 50%;
    transform: translateX(-50%);
    display: flex;
    gap: 10px;
    z-index: 100;
}

.slideshow-dot {
    width: 12px;
    height: 12px;
    border-radius: 50%;
    background-color: rgba(255,255,255,0.5);
    cursor: pointer;
    transition: all 0.3s;
}

.slideshow-dot.active {
    background-color: #667eea;
    width: 30px;
    border-radius: 6px;
}

/* ========== POSTS GRID ========== */
.posts-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 25px;
    margin-top: 30px;
}

.post-item {
    background: linear-gradient(135deg, #1a1a3e, #0f0f1e);
    border-radius: 15px;
    overflow: hidden;
    box-shadow: 0 5px 20px rgba(0, 0, 0, 0.3);
    transition: all 0.3s ease;
    border: 1px solid #2a2a4e;
}

.post-item:hover {
    transform: translateY(-8px);
    box-shadow: 0 15px 40px rgba(102, 126, 234, 0.3);
    border-color: #667eea;
}

.post-thumbnail {
    width: 100%;
    height: 200px;
    object-fit: cover;
    aspect-ratio: 16/9;
    transition: transform 0.3s;
}

.post-item:hover .post-thumbnail {
    transform: scale(1.05);
}

.post-thumbnail-container {
    overflow: hidden;
    position: relative;
}

.play-icon {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    width: 60px;
    height: 60px;
    background: rgba(102, 126, 234, 0.9);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    opacity: 0;
    transition: opacity 0.3s;
}

.post-item:hover .play-icon {
    opacity: 1;
}

.play-icon i {
    color: white;
    font-size: 24px;
    margin-left: 5px;
}

.post-info {
    padding: 20px;
}

.post-title {
    font-size: 16px;
    font-weight: 700;
    color: #fff;
    margin-bottom: 10px;
    line-height: 1.4;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.post-title a:hover {
    color: #667eea;
}

.post-excerpt {
    color: #909090;
    font-size: 13px;
    line-height: 1.6;
    display: -webkit-box;
    -webkit-line-clamp: 3;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.post-meta {
    display: flex;
    justify-content: space-between;
    margin-top: 15px;
    padding-top: 15px;
    border-top: 1px solid #2a2a4e;
    font-size: 12px;
    color: #707070;
}

/* ========== SIDEBAR ========== */
.sidebar {
    width: 300px;
    padding: 20px;
    background: rgba(20, 20, 40, 0.6);
    border-radius: 15px;
    margin-top: 30px;
}

.sidebar-widget {
    background: linear-gradient(135deg, #1a1a3e, #0f0f1e);
    border-radius: 12px;
    padding: 20px;
    margin-bottom: 20px;
    border: 1px solid #2a2a4e;
}

.sidebar-widget h3 {
    font-size: 16px;
    color: #fff;
    margin-bottom: 15px;
    padding-bottom: 10px;
    border-bottom: 2px solid #667eea;
}

.sidebar-widget ul {
    list-style: none;
}

.sidebar-widget li {
    padding: 8px 0;
    border-bottom: 1px solid #2a2a4e;
}

.sidebar-widget li:last-child {
    border-bottom: none;
}

.sidebar-widget a {
    color: #b0b0b0;
    font-size: 14px;
}

.sidebar-widget a:hover {
    color: #667eea;
    padding-left: 5px;
}

/* Search box */
.search-box {
    display: flex;
    background: #0a0a1a;
    border-radius: 8px;
    overflow: hidden;
    border: 1px solid #2a2a4e;
}

.search-box input {
    flex: 1;
    padding: 12px 15px;
    border: none;
    background: transparent;
    color: #e0e0e0;
    font-size: 14px;
}

.search-box input:focus {
    outline: none;
}

.search-box button {
    padding: 12px 15px;
    background: linear-gradient(135deg, #667eea, #764ba2);
    border: none;
    color: white;
    cursor: pointer;
    transition: background 0.3s;
}

.search-box button:hover {
    background: linear-gradient(135deg, #764ba2, #667eea);
}

/* ========== PAGINATION ========== */
.pagination {
    display: flex;
    justify-content: center;
    gap: 10px;
    margin: 40px 0;
}

.pagination a, .pagination span {
    padding: 10px 18px;
    background: linear-gradient(135deg, #1a1a3e, #0f0f1e);
    border-radius: 8px;
    color: #b0b0b0;
    font-weight: 600;
    transition: all 0.3s;
    border: 1px solid #2a2a4e;
}

.pagination a:hover {
    background: linear-gradient(135deg, #667eea, #764ba2);
    color: white;
    border-color: #667eea;
}

.pagination .current {
    background: linear-gradient(135deg, #667eea, #764ba2);
    color: white;
    border-color: #667eea;
}

/* ========== FOOTER ========== */
.footer {
    background: linear-gradient(135deg, #1a1a2e, #0f0f1e);
    padding: 30px;
    text-align: center;
    margin-top: 50px;
    border-top: 1px solid #2a2a4e;
}

.footer p {
    color: #707070;
    font-size: 14px;
}

.social-links {
    display: flex;
    justify-content: center;
    gap: 15px;
    margin-bottom: 20px;
}

.social-links a {
    width: 45px;
    height: 45px;
    border-radius: 50%;
    background: linear-gradient(135deg, #2a2a4e, #1a1a3e);
    display: flex;
    align-items: center;
    justify-content: center;
    color: #b0b0b0;
    font-size: 18px;
    transition: all 0.3s;
}

.social-links a:hover {
    background: linear-gradient(135deg, #667eea, #764ba2);
    color: white;
    transform: translateY(-5px);
}

/* ========== RESPONSIVE ========== */
@media screen and (max-width: 1200px) {
    .posts-grid {
        grid-template-columns: repeat(2, 1fr);
    }
}

@media screen and (max-width: 768px) {
    .container {
        flex-direction: column;
    }

    .vertical-menu {
        width: 100%;
        height: auto;
        position: relative;
    }

    .menu-header {
        padding: 15px;
    }

    .menu-header h1 {
        font-size: 20px;
    }

    .main-content {
        margin-left: 0;
        padding: 15px;
    }

    .posts-grid {
        grid-template-columns: 1fr;
    }

    .video-section {
        padding: 15px;
    }

    .video-section h2 {
        font-size: 18px;
    }

    .video-info h1 {
        font-size: 20px;
    }

    .episodes-grid {
        grid-template-columns: repeat(auto-fill, minmax(100px, 1fr));
        gap: 10px;
    }

    .episode-item {
        padding: 10px;
    }

    .episode-number {
        font-size: 18px;
    }

    .slideshow-slide img {
        height: 200px;
    }

    .slideshow-slide-content h3 {
        font-size: 18px;
    }

    .share-buttons {
        flex-direction: column;
    }

    .share-btn {
        justify-content: center;
    }
}

/* ========== LOADING SPINNER ========== */
.video-loading {
    display: flex;
    justify-content: center;
    align-items: center;
    height: 300px;
    background: #0a0a1a;
    border-radius: 10px;
}

.spinner {
    width: 50px;
    height: 50px;
    border: 4px solid #2a2a4e;
    border-top-color: #667eea;
    border-radius: 50%;
    animation: spin 1s linear infinite;
}

@keyframes spin {
    to { transform: rotate(360deg); }
}

/* ========== SCROLLBAR ========== */
::-webkit-scrollbar {
    width: 8px;
}

::-webkit-scrollbar-track {
    background: #0a0a1a;
}

::-webkit-scrollbar-thumb {
    background: linear-gradient(135deg, #667eea, #764ba2);
    border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
    background: linear-gradient(135deg, #764ba2, #667eea);
}

body.script:
//
    // Slideshow functionality
    let slideIndex = 1;
    showSlides(slideIndex);

    let slideTimer = setInterval(() => {
        plusSlides(1);
    }, 5000);

    function plusSlides(n) {
        showSlides(slideIndex += n);
        resetTimer();
    }

    function currentSlide(n) {
        showSlides(slideIndex = n);
        resetTimer();
    }

    function showSlides(n) {
        let i;
        let slides = document.getElementsByClassName("slideshow-slide");
        let dots = document.getElementsByClassName("slideshow-dot");

        if (n > slides.length) {slideIndex = 1}
        if (n < 1) {slideIndex = slides.length}

        for (i = 0; i < slides.length; i++) {
            slides[i].style.display = "none";
        }

        for (i = 0; i < dots.length; i++) {
            dots[i].className = dots[i].className.replace(" active", "");
        }

        slides[slideIndex-1].style.display = "block";
        dots[slideIndex-1].className += " active";
    }

    function resetTimer() {
        clearInterval(slideTimer);
        slideTimer = setInterval(() => {
            plusSlides(1);
        }, 5000);
    }

    // Copy link function
    function copyLink() {
        const dummy = document.createElement('input');
        document.body.appendChild(dummy);
        dummy.value = window.location.href;
        dummy.select();
        document.execCommand('copy');
        document.body.removeChild(dummy);
        alert('Đã sao chép link!');
    }

    // Initialize Artplayer for post pages
    <b:if cond='data:blog.pageType == "item"'>
        document.addEventListener('DOMContentLoaded', function() {
            // Get video URL from post labels or use default
            let videoUrl = 'https://github.com/ghostminhtoan/private/releases/download/draft.picture/subtitle.edit.single.word.mp4';
            let posterUrl = '';

            // You can customize video URL based on post labels or custom fields
            // Example: Check for video URL in post body or labels

            var art = new Artplayer({
                container: '#artplayer',
                url: videoUrl,
                title: '<data:blog.pageName/>',
                poster: posterUrl,
                volume: 0.5,
                isLive: false,
                muted: false,
                autoplay: false,
                pip: true,
                autoSize: true,
                fullscreen: true,
                fullscreenWeb: true,
                setting: true,
                loop: false,
                playbackRate: true,
                aspectRatio: true,
                screenshot: true,
                hotkey: true,
                lang: 'vi',
                theme: '#667eea',
                control: {
                    show: true,
                },
            });

            // Episode click handlers
            document.querySelectorAll('.episode-item').forEach(item => {
                item.addEventListener('click', function() {
                    document.querySelectorAll('.episode-item').forEach(i => i.classList.remove('active'));
                    this.classList.add('active');
                    // Here you would load the corresponding episode
                    // For demo, just show alert
                    const episodeNum = this.querySelector('.episode-number').textContent;
                    console.log('Loading ' + episodeNum);
                });
            });
        });
    </b:if>
//
